                {
                    b.Property<int>("Id")
                        .ValueGeneratedOnAdd()
                        .HasColumnType("int");

                    SqlServerPropertyBuilderExtensions.UseIdentityColumn(b.Property<int>("Id"));

                    b.Property<string>("Locate")
                        .HasMaxLength(100)
                        .HasColumnType("nvarchar(100)");

                    b.Property<string>("Meaning")
                        .IsRequired()
                        .HasMaxLength(500)
                        .HasColumnType("nvarchar(500)");

                    b.Property<int>("WordId")
                        .HasColumnType("int");

                    b.HasKey("Id");

                    b.HasIndex("WordId");

                    b.ToTable("WordMeans");
                });

            modelBuilder.Entity("backend.Data.Models.RelatedWord", b =>
                {
                    b.HasOne("backend.Data.Models.Word", "TargetWord")
                        .WithMany("IncomingRelations")
                        .HasForeignKey("TargetWordId")
                        .OnDelete(DeleteBehavior.Restrict)
                        .IsRequired();

                    b.HasOne("backend.Data.Models.Word", "Word")
                        .WithMany("OutgoingRelations")
                        .HasForeignKey("WordId")
                        .OnDelete(DeleteBehavior.Cascade)
                        .IsRequired();

                    b.Navigation("TargetWord");

                    b.Navigation("Word");
                });

            modelBuilder.Entity("backend.Data.Models.WordMeans", b =>
                {
                    b.HasOne("backend.Data.Models.Word", "Word")
                        .WithMany("Meanings")
                        .HasForeignKey("WordId")
                        .OnDelete(DeleteBehavior.Cascade)
                        .IsRequired();

                    b.Navigation("Word");
                });

            modelBuilder.Entity("backend.Data.Models.Word", b =>
                {
                    b.Navigation("IncomingRelations");

                    b.Navigation("Meanings");

                    b.Navigation("OutgoingRelations");
                });
